Here's a complete test class using modern MSTest v3+ patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Helper to create a DataFetcher with a fake HTTP response
    private static DataFetcher CreateFetcher(
        HttpStatusCode statusCode,
        string content = "")
    {
        var handler = new MockHandler(new HttpResponseMessage(statusCode)
        {
            Content = new StringContent(content)
        });
        return new DataFetcher(new HttpClient(handler));
    }

    // --- Async basics: just return Task, MSTest awaits it ---

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var fetcher = CreateFetcher(HttpStatusCode.OK, "hello");

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnErrorStatus()
    {
        var fetcher = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Timeouts: [Timeout] sets a per-test deadline ---
    //     MSTest cancels TestContext.CancellationTokenSource when it expires.

    [TestMethod]
    [Timeout(3000)] // milliseconds
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var fetcher = CreateFetcher(HttpStatusCode.OK, "fast");

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // --- CancellationToken: verify the method honors cancellation ---

    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        var fetcher = CreateFetcher(HttpStatusCode.OK, "data");
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        using var cts = new CancellationTokenSource();
        // Handler cancels the token mid-flight
        var handler = new MockHandler(_ =>
        {
            cts.Cancel();
            throw new OperationCanceledException(cts.Token);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Minimal mock handler (no third-party dependency) ---

    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, HttpResponseMessage> _factory;

        public MockHandler(HttpResponseMessage response)
            : this(_ => response) { }

        public MockHandler(Func<HttpRequestMessage, HttpResponseMessage> factory)
            => _factory = factory;

        // Also accepts an action-that-throws overload for cancellation tests
        public MockHandler(Action<HttpRequestMessage> action)
            : this(req => { action(req); return null!; }) { }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_factory(request));
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` — MSTest awaits it automatically |
| **Timeouts** | `[Timeout(ms)]` — fails the test if it exceeds the deadline |
| **Cancellation** | Pass a pre-cancelled or mid-flight-cancelled `CancellationToken` and assert `TaskCanceledException` |
| **No external mocks** | Custom `HttpMessageHandler` avoids a Moq/NSubstitute dependency |

> **Tip:** In MSTest v3+ you can also access `TestContext.CancellationTokenSource.Token` inside the test body — it's wired to the `[Timeout]` attribute, so you can forward it directly to the method under test for integrated timeout+cancellation testing.
